<?php if(!class_exists('Rain\Tpl')){exit;}?><div class="content-wrapper"><section class="content-header painel-topo"><h1><i class="bi bi-person-lock"></i> Segurança dos Usuários<small>Ativar, inativar e bloquear login</small></h1></section><section class="content"><div class="card mb-4 painel-formulario"><div class="card-header cabecalho-formulario"><div class="card-title">Usuários</div></div><div class="card-body p-0"><table class="table"><thead><tr><th>Nome</th><th>CPF</th><th>Perfil</th><th>Usuário</th><th>Funcionário</th><th>Ações</th></tr></thead><tbody><?php $counter1=-1;  if( isset($usuarios) && ( is_array($usuarios) || $usuarios instanceof Traversable ) && sizeof($usuarios) ) foreach( $usuarios as $key1 => $value1 ){ $counter1++; ?><tr><td><?php echo htmlspecialchars( $value1["nome_funcionario"], ENT_COMPAT, 'UTF-8', FALSE ); ?></td><td><?php echo htmlspecialchars( $value1["cpf"], ENT_COMPAT, 'UTF-8', FALSE ); ?></td><td><?php echo htmlspecialchars( $value1["perfil"], ENT_COMPAT, 'UTF-8', FALSE ); ?></td><td><?php if( $value1["usuario_ativo"] == 1 ){ ?><span class="badge bg-success">Ativo</span><?php }else{ ?><span class="badge bg-danger">Bloqueado</span><?php } ?></td><td><?php if( $value1["funcionario_ativo"] == 1 ){ ?><span class="badge bg-success">Ativo</span><?php }else{ ?><span class="badge bg-secondary">Inativo</span><?php } ?></td><td><form method="post" action="/admin/usuarios/<?php echo htmlspecialchars( $value1["id_usuario"], ENT_COMPAT, 'UTF-8', FALSE ); ?>/status" style="display:inline-block"><input type="hidden" name="ativo" value="<?php if( $value1["usuario_ativo"] == 1 ){ ?>0<?php }else{ ?>1<?php } ?>"><button class="btn btn-xs btn-warning" type="submit"><?php if( $value1["usuario_ativo"] == 1 ){ ?>Bloquear login<?php }else{ ?>Ativar login<?php } ?></button></form> <form method="post" action="/admin/funcionarios/<?php echo htmlspecialchars( $value1["id_pessoa"], ENT_COMPAT, 'UTF-8', FALSE ); ?>/status-funcionario" style="display:inline-block"><input type="hidden" name="ativo" value="<?php if( $value1["funcionario_ativo"] == 1 ){ ?>0<?php }else{ ?>1<?php } ?>"><button class="btn btn-xs btn-default" type="submit"><?php if( $value1["funcionario_ativo"] == 1 ){ ?>Inativar funcionário<?php }else{ ?>Ativar funcionário<?php } ?></button></form></td></tr><?php } ?></tbody></table></div></div></section></div>